// Minimal validation + message formatting
const data = $input.first().json;


// Normalize Mexican mobile phone number (critical for WhatsApp)
let phoneNumber = data.body.phone_number.toString().replace(/\D/g, ''); // Clean non-digits

// If 13 digits starting with 521 (Mexican mobile with "1"), remove the "1"
if (phoneNumber.startsWith('521') && phoneNumber.length === 13) {
  phoneNumber = '52' + phoneNumber.substring(3); // "5215551457890" → "525551457890"
}

// If 10 digits (no country code), add Mexico code
if (phoneNumber.length === 10) {
  phoneNumber = '52' + phoneNumber; // "5563125678" → "525563125678"
}

// Format amount as Mexican Pesos
const formattedAmount = new Intl.NumberFormat('es-MX', {
  style: 'currency',
  currency: 'MXN'
}).format(data.body.amount);

// Build WhatsApp message (Spanish, formal tone)
const message = `¡Estimado cliente!

Su pago ha sido confirmado exitosamente. ✅

📋 *Póliza:* ${data.body.policy_number}
💵 *Monto:* ${formattedAmount}
📅 *Estado:* Activa

Gracias por confiar en nosotros. Su póliza ya está vigente y lo protege a partir de este momento.

Si tiene alguna duda o requiere asistencia, no dude en contactarnos.

Atentamente,
_Equipo de Atención al Cliente_`;

// Return formatted data for WhatsApp node
return {
  json: {
    to: phoneNumber,
    message: message,
    policy_number: data.body.policy_number,
    amount: formattedAmount,
    transaction_id: data.transaction_id,
    timestamp: new Date().toISOString()
  }
};

const formattedData = $('Format & Validate Message').first().json;
const dbResult = $input.first().json;

console.log('W2: session marked completed', {
  sessionId: dbResult.session_id,
  phone: formattedData.to,
  phase: dbResult.conversation_phase
});

return [{ json: formattedData }]; // Restore full formatted message for Send WhatsApp Message
